  padding-left: 10px;
}
.chat-thinking summary {
  cursor: pointer;
  font-style: italic;
  color: #666;
}
.chat-thinking-content {
  white-space: pre-wrap;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  margin-top: 4px;
  max-height: 200px;
  overflow-y: auto;
}

/* Tool call cards */
.chat-tool-card {
  margin: 6px 0;
  border: 1px solid #333;
  border-radius: 6px;
  background: #1a1a1a;
  font-size: 13px;
}

.chat-tool-header {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 10px;
  cursor: pointer;
  list-style: none;
}
.chat-tool-header::-webkit-details-marker { display: none; }

.chat-tool-icon { font-size: 14px; }

.chat-tool-title {
  flex: 1;
  font-family: var(--font-mono, monospace);
  color: #ccc;
}

.chat-tool-path {
  font-family: var(--font-mono, monospace);
  color: #666;
  font-size: 11px;
}

.chat-tool-status {
  font-family: var(--font-mono, monospace);
  font-size: 11px;
  padding: 1px 6px;
  border-radius: 3px;
  text-transform: uppercase;
}
.chat-tool-status.pending { color: #888; background: rgba(255,255,255,0.05); }
.chat-tool-status.in_progress { color: var(--accent, #FF4D00); background: rgba(255,77,0,0.1); }
.chat-tool-status.completed { color: #4a4; background: rgba(68,170,68,0.1); }
.chat-tool-status.failed { color: #d44; background: rgba(221,68,68,0.1); }

.chat-tool-body {
  padding: 0 10px 8px;
}

.chat-tool-output {
  background: #0d0d0d;
  border: 1px solid #2a2a2a;
  border-radius: 4px;
  padding: 8px;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  white-space: pre-wrap;
  word-break: break-all;
  max-height: 300px;

