    --text-primary: #EEEEEE;
    --text-secondary: #BBBBBB;
    --text-muted: #777777;

    --border: #333333;
    --border-light: #2a2a2a;

    --accent-dim: rgba(255, 77, 0, 0.15);

    --bg-code: #0d0d0d;
    --border-code: #333333;
    --bg-code-inline: rgba(255, 255, 255, 0.08);
    --bg-table-header: rgba(255, 255, 255, 0.05);
    --border-table: #444444;

    --bg-tool-card: #1a1a1a;

    --status-done: #888888;
    --status-likely-done: #666666;

    --badge-claude: #DDDDDD;
    --badge-codex: #AAAAAA;
  }

  .status-label.done {
