  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  padding: 4px 8px;
}
.chat-panel-close:hover { color: var(--text-primary); }

toolUseResult.oldString:
.chat-panel-close {
  font-size: 18px;
