function switchChatTab(tabId) {
  if (!chatTabs[tabId]) return;
  if (activeChatTabId && chatTabs[activeChatTabId]) {
    chatTabs[activeChatTabId].container.classList.remove("active");
  }
  activeChatTabId = tabId;
  chatTabs[tabId].container.classList.add("active");
  renderChatTabs();
  renderTurnSidebar(chatTabs[tabId]);
  updateInputState();
  scrollToBottom();

def build_content_blocks(msg: dict) -> list:
    """Build ACP content blocks from a WebSocket user_message payload.

    Returns a list of text/image blocks, or an empty list if there's no content.
    """
    text = msg.get("text", "").strip()
    images = msg.get("images", [])
    blocks: list = []
    if text:
        blocks.append(acp.text_block(text))
    for img in images:
        blocks.append(acp.image_block(img["data"], img["mimeType"]))
    return blocks


